async (page) => {
  // Navigate directly to search results with params
  const url = `https://www.booking.com/searchresults.html?ss=${encodeURIComponent('{{destination}}')}&checkin={{checkin}}&checkout={{checkout}}&group_adults={{guests}}&no_rooms=1&group_children=0`;
  await page.goto(url);
  await page.waitForLoadState('load');

  // Dismiss cookie consent
  try {
    const cookieBtn = page.locator('#onetrust-accept-btn-handler');
    if (await cookieBtn.isVisible({ timeout: 2000 })) await cookieBtn.click();
  } catch {}

  // Dismiss Genius sign-in popup
  try {
    const dismissBtn = page.locator('[aria-label="Dismiss sign-in info."], [aria-label="Dismiss sign in information."]').first();
    if (await dismissBtn.isVisible({ timeout: 2000 })) await dismissBtn.click();
  } catch {}

  // Dismiss any dialog overlays
  try {
    const closeBtn = page.locator('[role="dialog"] button[aria-label="Close"], [role="dialog"] [aria-label="Dismiss"]').first();
    if (await closeBtn.isVisible({ timeout: 1000 })) await closeBtn.click();
  } catch {}

  return { success: true, url: page.url() };
}

async (page) => {
  // Wait for property cards to load
  await page.waitForSelector('[data-testid="property-card"]', { timeout: 15000 });

  // Extract top 5 hotels with details
  const hotels = await page.$$eval('[data-testid="property-card"]', (cards) => {
    return cards.slice(0, 5).map((card, i) => {
      const title = card.querySelector('[data-testid="title"]');
      const price = card.querySelector('[data-testid="price-and-discounted-price"]');
      const review = card.querySelector('[data-testid="review-score"]');
      const distance = card.querySelector('[data-testid="distance"]');
      const genius = card.querySelector('[class*="genius"], [data-testid*="genius"]');
      const originalPrice = card.querySelector('[aria-hidden="true"] span[aria-hidden="true"]');
      const taxInfo = card.querySelector('[data-testid="taxes-and-charges"]');

      return {
        index: i + 1,
        name: title?.textContent?.trim() || 'Unknown',
        price: price?.textContent?.trim() || 'N/A',
        originalPrice: originalPrice?.textContent?.trim() || null,
        taxInfo: taxInfo?.textContent?.trim() || null,
        reviewScore: review?.textContent?.trim() || 'No reviews',
        distance: distance?.textContent?.trim() || '',
        hasGeniusDiscount: !!genius,
      };
    });
  });

  return { success: true, hotels, count: hotels.length };
}

