async (page, context) => {
  // Determine which hotel to click based on user's response
  const choice = context.selectedHotelIndex || '1';
  let idx = parseInt(choice) - 1;
  if (isNaN(idx) || idx < 0) idx = 0;

  // Click the hotel's 'See availability' link
  const cards = page.locator('[data-testid="property-card"]');
  const card = cards.nth(idx);
  const link = card.locator('a[data-testid="title-link"], a:has-text("See availability"), a:has-text("Show prices")').first();
  await link.click();
  await page.waitForLoadState('load');
  await page.waitForTimeout(2000);

  // Dismiss any popup on hotel page
  try {
    const closeBtn = page.locator('[aria-label="Close"], [role="dialog"] button:has-text("×")').first();
    if (await closeBtn.isVisible({ timeout: 1500 })) await closeBtn.click();
  } catch {}

  // Extract hotel name from the page
  const hotelName = await page.locator('h2[class*="hotel_name"], h2#hp_hotel_name, [data-testid="header-title"]').first().textContent().catch(() => 'Hotel');

  return { success: true, hotelName: hotelName?.trim(), url: page.url() };
}

async (page) => {
  // Scroll to rooms section
  const roomsSection = page.locator('#rooms_and_availability, [data-testid="room-table"], table.hprt-table').first();
  if (await roomsSection.isVisible({ timeout: 5000 })) {
    await roomsSection.scrollIntoViewIfNeeded();
  }
  await page.waitForTimeout(1500);

  // Extract room types
  const rooms = await page.$$eval('.hprt-table tr.js-rt-block-row, [data-testid="room-type"]', (rows) => {
    const seen = new Set();
    return rows.slice(0, 8).reduce((acc, row, i) => {
      const name = row.querySelector('.hprt-roomtype-icon-link, [data-testid="room-name"]');
      const price = row.querySelector('.bui-price-display__value, .prco-valign-middle-helper, [data-testid="room-price"]');
      const occupancy = row.querySelector('.hprt-occupancy-occupancy-info, [data-testid="occupancy"]');
      const conditions = row.querySelector('.hprt-conditions, [data-testid="cancellation-policy"]');
      const roomName = name?.textContent?.trim() || '';

      if (roomName && !seen.has(roomName)) {
        seen.add(roomName);
        acc.push({
          index: acc.length + 1,
          name: roomName,
          price: price?.textContent?.trim() || 'N/A',
          occupancy: occupancy?.textContent?.trim() || '',
          cancellation: conditions?.textContent?.trim()?.substring(0, 80) || 'Check details',
        });
      }
      return acc;
    }, []);
  });

  // Get hotel-level info
  const hotelRating = await page.locator('[data-testid="rating-stars"], [class*="star"]').first().textContent().catch(() => '');
  const hotelScore = await page.locator('[data-testid="review-score-component"]').first().textContent().catch(() => '');

  return { success: true, rooms, hotelRating: hotelRating?.trim(), hotelScore: hotelScore?.trim() };
}

