async (page, context) => {
  const choice = context.selectedRoomIndex || '1';
  let idx = parseInt(choice) - 1;
  if (isNaN(idx) || idx < 0) idx = 0;

  // Try to select the room by clicking its row's Reserve/Select button
  // Booking.com has dropdowns for room count + a Reserve button
  const roomRows = page.locator('.hprt-table tr.js-rt-block-row, [data-testid="room-type"]');
  const targetRow = roomRows.nth(idx);

  // Some hotels have a quantity dropdown — select 1 room
  try {
    const dropdown = targetRow.locator('select.hprt-nos-select, [data-testid="select-room-count"]').first();
    if (await dropdown.isVisible({ timeout: 2000 })) {
      await dropdown.selectOption('1');
      await page.waitForTimeout(500);
    }
  } catch {}

  // Click Reserve/I'll reserve/Book now button
  const reserveBtn = page.locator(
    'button:has-text("Reserve"), button:has-text("I\'ll reserve"), ' +
    'button:has-text("Book now"), input[value="Reserve"], ' +
    '[data-testid="submit-room-selection"], .hprt-reservation-cta button'
  ).first();

  if (await reserveBtn.isVisible({ timeout: 5000 })) {
    await reserveBtn.click();
    await page.waitForLoadState('load');
    await page.waitForTimeout(2000);
  }

  return { success: true, url: page.url() };
}

async (page, context) => {
  const currentUrl = page.url();
  if (!currentUrl.includes('book') && !currentUrl.includes('checkout') && !currentUrl.includes('reservation')) {
    return { success: true, skipped: true, reason: 'Not on booking form yet' };
  }

  // Fill first name — use data-testid (discovered from live test)
  const firstName = page.locator('[data-testid="user-details-firstname"], [name="firstname"], #firstname').first();
  if (await firstName.isVisible({ timeout: 3000 })) {
    const val = await firstName.inputValue();
    if (!val && context.userFirstName) {
      await firstName.fill(context.userFirstName);
    }
  }

  // Fill last name
  const lastName = page.locator('[data-testid="user-details-lastname"], [name="lastname"], #lastname').first();
  if (await lastName.isVisible({ timeout: 1000 })) {
    const val = await lastName.inputValue();
    if (!val && context.userLastName) {
      await lastName.fill(context.userLastName);
    }
  }

  // Fill email
  const emailField = page.locator('[data-testid="user-details-email"], [name="email"], #email').first();
  if (await emailField.isVisible({ timeout: 1000 })) {
    const val = await emailField.inputValue();
    if (!val && context.userEmail) {
      await emailField.fill(context.userEmail);
    }
  }

  // Fill phone
  const phoneField = page.locator('[data-testid="phone-number-input"], [name="phone"], [name="cc_phone"]').first();
  if (await phoneField.isVisible({ timeout: 1000 })) {
    const val = await phoneField.inputValue();
    if (!val && context.userPhone) {
      await phoneField.fill(context.userPhone);
    }
  }

  // Handle "Are you travelling for work?" — default No
  try {
    const workNo = page.locator('[data-testid="booking-travel-purpose-no"], label:has-text("No"):near(text("work"))').first();
    if (await workNo.isVisible({ timeout: 1000 })) await workNo.click();
  } catch {}

  // Handle special requests
  if (context.specialRequests) {
    try {
      const reqField = page.locator('[name="special_requests"], textarea[id*="request"]').first();
      if (await reqField.isVisible({ timeout: 1000 })) {
        await reqField.fill(context.specialRequests);
      }
    } catch {}
  }

  return { success: true, filled: true };
}

async (page) => {
  // Click Next/Continue/Final details button
  const nextBtn = page.locator(
    'button:has-text("Next: Final details"), button:has-text("Final details"), ' +
    'button:has-text("Continue"), button:has-text("Next step")'
  ).first();

  if (await nextBtn.isVisible({ timeout: 3000 })) {
    await nextBtn.click();
    await page.waitForLoadState('load');
    await page.waitForTimeout(2000);
  }

  // Extract final price including taxes
  let totalPrice = 'N/A';
  let geniusDiscount = null;
  let taxesIncluded = null;

  try {
    // Try multiple price selectors
    const priceSelectors = [
      '[data-testid="total-price"]',
      '.bui-price-display__value',
      '.pricebreak-price',
      '.bp-price-display__value',
      '[class*="total"] [class*="price"]',
      '.totalPrice'
    ];
    for (const sel of priceSelectors) {
      const el = page.locator(sel).first();
      if (await el.isVisible({ timeout: 1000 }).catch(() => false)) {
        totalPrice = (await el.textContent())?.trim() || totalPrice;
        break;
      }
    }
  } catch {}

  // Extract Genius discount amount
  try {
    const discountEl = page.locator('[class*="genius"] [class*="discount"], [data-testid*="genius"]').first();
    if (await discountEl.isVisible({ timeout: 1000 })) {
      geniusDiscount = (await discountEl.textContent())?.trim();
    }
  } catch {}

  // Extract tax info
  try {
    const taxEl = page.locator('[data-testid="taxes-and-charges"], [class*="tax"]').first();
    if (await taxEl.isVisible({ timeout: 1000 })) {
      taxesIncluded = (await taxEl.textContent())?.trim();
    }
  } catch {}

  return {
    success: true,
    totalPrice,
    geniusDiscount,
    taxesIncluded,
    url: page.url()
  };
}

