async (page) => {
  await page.waitForTimeout(3000);

  const confirmUrl = page.url();
  const pageTitle = await page.title();

  // Check if we're on a confirmation page
  const isConfirmed = confirmUrl.includes('confirmation') ||
    confirmUrl.includes('success') ||
    confirmUrl.includes('thank') ||
    pageTitle.toLowerCase().includes('confirmed') ||
    pageTitle.toLowerCase().includes('booked');

  // Extract confirmation number
  let confirmationNumber = '';
  try {
    const confSelectors = [
      '[data-testid="confirmation-number"]',
      '[class*="confirmation"]',
      '[class*="booking-number"]',
      '[class*="reference"]',
      'span:has-text("Confirmation")',
      'div:has-text("Booking number")'
    ];
    for (const sel of confSelectors) {
      const el = page.locator(sel).first();
      if (await el.isVisible({ timeout: 1000 }).catch(() => false)) {
        const text = await el.textContent();
        // Extract just the number/code part
        const numMatch = text?.match(/[A-Z0-9]{6,}/i);
        if (numMatch) {
          confirmationNumber = numMatch[0];
          break;
        }
        confirmationNumber = text?.trim() || '';
        break;
      }
    }
  } catch {}

  // Extract confirmed hotel name
  let confirmedHotel = '';
  try {
    const hotelEl = page.locator('[data-testid="hotel-name"], h1, [class*="hotel-name"]').first();
    if (await hotelEl.isVisible({ timeout: 1000 })) {
      confirmedHotel = (await hotelEl.textContent())?.trim() || '';
    }
  } catch {}

  // Extract confirmed dates
  let confirmedDates = '';
  try {
    const dateEl = page.locator('[data-testid="check-in-date"], [class*="date"]').first();
    if (await dateEl.isVisible({ timeout: 1000 })) {
      confirmedDates = (await dateEl.textContent())?.trim() || '';
    }
  } catch {}

  // Extract confirmed price
  let confirmedPrice = '';
  try {
    const priceEl = page.locator('[data-testid="total-price"], [class*="total"] [class*="price"]').first();
    if (await priceEl.isVisible({ timeout: 1000 })) {
      confirmedPrice = (await priceEl.textContent())?.trim() || '';
    }
  } catch {}

  return {
    success: true,
    isConfirmed,
    confirmationNumber,
    hotelName: confirmedHotel,
    dates: confirmedDates,
    totalPaid: confirmedPrice,
    url: confirmUrl
  };
}
